{
  "terms": [
    {
      "term": "Generation",
      "simpleDefinition": "The process of converting energy sources like gas, wind, or nuclear into electrical energy.",
      "anchor": "The 'starting point' of the electrical journey at a power station.",
      "misconception": "Thinking electricity is created from nothing; it is always converted from another energy source."
    },
    {
      "term": "Transmission",
      "simpleDefinition": "The bulk movement of electricity over long distances at very high voltages.",
      "anchor": "The 'motorway' system of the electrical grid using large steel pylons.",
      "misconception": "Confusing transmission with distribution, which is the local delivery to homes."
    },
    {
      "term": "Micro-generation",
      "simpleDefinition": "Small-scale production of electricity at or near the place where it is used.",
      "anchor": "Solar panels (PV) on a house roof or a small wind turbine in a garden.",
      "misconception": "Assuming all renewable energy is micro-generation; large wind farms are actually grid-scale generation."
    },
    {
      "term": "Transmission Voltages",
      "simpleDefinition": "The specific high-pressure levels used for the UK grid: 400 kV, 275 kV, and 132 kV.",
      "anchor": "The three 'magic numbers' for the UK transmission network.",
      "misconception": "Thinking 132 kV is a low distribution voltage because it is the smallest of the three."
    },
    {
      "term": "I²R Losses",
      "simpleDefinition": "Energy lost as heat when current flows through the resistance of a cable.",
      "anchor": "A cable or appliance getting warm during use.",
      "misconception": "Believing high voltage is used to make electricity 'faster' rather than to reduce heat losses."
    }
  ],
  "anchorPhrases": [
    "Transmission is the motorway of the grid.",
    "400, 275, and 132: the three transmission voltages.",
    "High voltage means low current, which means less heat loss.",
    "Micro-generation happens at the point of use."
  ],
  "misconceptionTargets": [
    "Confusing transmission (long distance) with distribution (local).",
    "Thinking all renewables are small-scale or 'micro'.",
    "Believing high voltage is used for 'extra power' rather than efficiency."
  ]
}

{
  "teachChecks": [
    {
      "title": "Centralised Generation Overview",
      "basicQuestions": [
        {
          "questionText": "What is the name of the nationwide network used to transport electricity from central power stations?",
          "answerGuidance": [
            "National Grid",
            "The National Grid"
          ],
          "hint": "It is the interconnected system that links power stations to the local networks.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "In a centralised system, where is electricity produced before it enters the distribution network?",
          "answerGuidance": [
            "Power stations",
            "Central power stations"
          ],
          "hint": "These are the large-scale facilities like gas or nuclear plants.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Does electricity leave a power station at the same voltage used in a domestic home?",
          "answerGuidance": [
            "No",
            "False"
          ],
          "hint": "Think about whether the voltage needs to be changed for long-distance travel.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why is it important for an electrician to distinguish between the point of generation and the local distribution network?",
      "deeperAnswerGuidance": [
        "Understanding the origin of energy",
        "Recognising the journey electricity takes before the intake",
        "Identifying where the supply enters the local system",
        "Distinguishing between grid-scale and local-scale infrastructure"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Consider the path electricity takes from the power station to the consumer's property."
    },
    {
      "title": "Transmission Voltage Identification",
      "basicQuestions": [
        {
          "questionText": "What is the highest standard transmission voltage used in the UK?",
          "answerGuidance": [
            "400 kV",
            "400,000 Volts"
          ],
          "hint": "It is the largest of the three standard transmission numbers.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which transmission voltage is the lowest of the three standard UK levels?",
          "answerGuidance": [
            "132 kV",
            "132,000 Volts"
          ],
          "hint": "This is often mistaken for a distribution voltage but is actually for transmission.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP3"
          ]
        },
        {
          "questionText": "What is the middle standard transmission voltage used in the UK grid?",
          "answerGuidance": [
            "275 kV",
            "275,000 Volts"
          ],
          "hint": "It sits between 132 kV and 400 kV.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        }
      ],
      "deeperQuestionText": "Why is 132 kV specifically categorised as a transmission voltage rather than a distribution voltage in the UK?",
      "deeperAnswerGuidance": [
        "It is part of the bulk movement of electricity",
        "It belongs to the transmission grid hierarchy",
        "It is one of the three defined transmission levels",
        "It operates at a higher level than local 33 kV or 11 kV systems"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Think about the standard definitions used in the C&G 2365 curriculum for the UK grid."
    },
    {
      "title": "Large-Scale Generation Methods",
      "basicQuestions": [
        {
          "questionText": "Which fossil fuel is commonly used for large-scale generation alongside coal and oil?",
          "answerGuidance": [
            "Gas",
            "Natural gas"
          ],
          "hint": "This is a very common fuel for modern power stations.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which large-scale generation method uses atomic reactions to produce heat?",
          "answerGuidance": [
            "Nuclear"
          ],
          "hint": "This method provides a constant 'base load' for the grid.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the term for large-scale electricity generation using the movement of water?",
          "answerGuidance": [
            "Hydro",
            "Hydroelectric"
          ],
          "hint": "Think of dams and large river systems.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        }
      ],
      "deeperQuestionText": "How does the use of a diverse energy mix, including wind, wave, and nuclear, benefit the national supply?",
      "deeperAnswerGuidance": [
        "Ensures a reliable bulk supply",
        "Reduces reliance on a single fuel source",
        "Maintains grid stability",
        "Balances renewable and constant power sources"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider what happens if one source, like wind, is not available."
    },
    {
      "title": "Micro-Generation and Local Supply",
      "basicQuestions": [
        {
          "questionText": "Where is micro-generation typically located in relation to the consumer?",
          "answerGuidance": [
            "Point of use",
            "At or near the place where it is used",
            "On-site"
          ],
          "hint": "Think about where solar panels are usually installed.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What does the abbreviation PV stand for in solar micro-generation?",
          "answerGuidance": [
            "Photovoltaic"
          ],
          "hint": "It refers to the process of converting light directly into electricity.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is a common example of a micro-generation technology found on domestic roofs?",
          "answerGuidance": [
            "Solar panels",
            "Photovoltaic panels",
            "PV panels"
          ],
          "hint": "These capture energy from the sun.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why is a large offshore wind farm not classified as micro-generation, even though it uses renewable energy?",
      "deeperAnswerGuidance": [
        "It provides bulk supply to the grid",
        "It is not located at the point of use",
        "It is large-scale generation",
        "It is intended for wide-scale distribution rather than local consumption"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Compare the location and the intended destination of the electricity produced."
    },
    {
      "title": "The Logic of High Voltage Transmission",
      "basicQuestions": [
        {
          "questionText": "When voltage is increased for transmission, what happens to the level of current?",
          "answerGuidance": [
            "Decreases",
            "It goes down",
            "Lower current"
          ],
          "hint": "Voltage and current have an inverse relationship in this context.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What specific type of energy loss is reduced by using high voltage and low current?",
          "answerGuidance": [
            "Heat loss",
            "Heat",
            "Thermal loss"
          ],
          "hint": "Think about what happens to a cable when it carries too much current.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the technical term for power losses caused by resistance in a conductor?",
          "answerGuidance": [
            "I²R losses",
            "I squared R"
          ],
          "hint": "It is a formula representing current squared multiplied by resistance.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "How does the relationship between voltage and heat loss justify the use of transformers at power stations?",
      "deeperAnswerGuidance": [
        "Transformers step up the voltage",
        "Higher voltage allows for lower current",
        "Lower current reduces I²R heat losses",
        "This makes long-distance transmission efficient",
        "Prevents energy being wasted as heat in the cables"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Connect the need for efficiency over long distances to the physical properties of electricity."
    }
  ]
}

